import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Random Image API ve Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Other/random-image-api-and-public-gallery.md","filePath":"tr-TR/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),d={name:"tr-TR/Other/random-image-api-and-public-gallery.md"};function l(n,e,o,s,c,p){return t(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="random-image-api-ve-public-gallery" tabindex="-1">Random Image API ve Public Gallery <a class="header-anchor" href="#random-image-api-ve-public-gallery" aria-label="Permalink to &quot;Random Image API ve Public Gallery&quot;">​</a></h1><p>İki özellik de şuradan yapılandırılır:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API, seçilen dizinlerden rastgele bir dosya döndürür. Site arka planları, avatar rotasyonu veya dış sayfalardan rastgele görsel çağrıları için kullanışlıdır.</p><p>Etkinleştirildikten sonra şunu kullanın:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-ayarları" tabindex="-1">Random Image API Ayarları <a class="header-anchor" href="#random-image-api-ayarları" aria-label="Permalink to &quot;Random Image API Ayarları&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seçenek</th><th>Amaç</th></tr></thead><tbody><tr><td>Enable</td><td><code>/random</code> endpoint&#39;ini açar veya kapatır. Kapalıyken erişim yasaktır.</td></tr><tr><td>Directories</td><td>Random API&#39;nin kullanabileceği dizinleri sınırlar. Buraya dahil edilmeyen dizinler API tarafından kullanılamaz.</td></tr><tr><td>Call demo</td><td>Doğrudan kopyalayabileceğiniz random API bağlantıları oluşturur.</td></tr></tbody></table><p>Birden fazla dizin seçebilirsiniz. Örneğin yalnızca <code>/landscape/</code> ve <code>/portrait/</code> izinliyse random API yalnızca bu dizinlerden ve alt dizinlerinden dosya seçebilir.</p><h2 id="random-image-api-parametreleri" tabindex="-1">Random Image API Parametreleri <a class="header-anchor" href="#random-image-api-parametreleri" aria-label="Permalink to &quot;Random Image API Parametreleri&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parametre</th><th>Örnek</th><th>Amaç</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Random directory belirtir.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Media type belirtir. <code>image</code>, <code>video</code>, <code>audio</code> veya virgülle ayrılmış kombinasyonlar kullanın.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Görsel yönünü filtreler. <code>portrait</code>, <code>landscape</code> veya <code>auto</code> kullanın.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Dönüş formatı. Boşsa redirect, <code>url</code> plain text URL, <code>json</code> JSON döndürür.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td><code>type=url</code> ile birlikte tam URL döndürmek için kullanılır.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Age rating değerine göre filtreler.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Yalnızca bu tags değerlerini içeren dosyaları döndürür.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Bu tags değerlerini içeren dosyaları hariç tutar.</td></tr></tbody></table><h2 id="donus-formatları" tabindex="-1">Dönüş Formatları <a class="header-anchor" href="#donus-formatları" aria-label="Permalink to &quot;Dönüş Formatları&quot;">​</a></h2><p><code>type</code> olmadan API doğrudan rastgele dosya URL&#39;sine yönlendirir.</p><p><code>type=url</code> ile metin URL döndürür.</p><p><code>type=json</code> ile file URL, file ID, file name, file type, tags, rating ve ilgili metadata dahil dosya bilgilerini döndürür.</p><h2 id="erisim-kuralları" tabindex="-1">Erişim Kuralları <a class="header-anchor" href="#erisim-kuralları" aria-label="Permalink to &quot;Erişim Kuralları&quot;">​</a></h2><p>Random Image API public access rules kurallarına uyar:</p><table tabindex="0"><thead><tr><th>Kural</th><th>Etki</th></tr></thead><tbody><tr><td>Directory restriction</td><td>Yalnızca izinli dizinlerdeki dosyalar seçilebilir.</td></tr><tr><td>Blocklist</td><td>Blocklisted files random pool dışında bırakılır.</td></tr><tr><td>Allowlist mode</td><td>Etkin olduğunda yalnızca public access için izinli dosyalar döner.</td></tr><tr><td>Age rating</td><td>R12, R16, R18 ve benzeri içerik geçerli access mode ile filtrelenir.</td></tr></tbody></table><p>Filtrelemeden sonra eşleşen dosya yoksa API eşleşen sonuç olmadığını döndürür.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API hız için dizin candidate pools değerlerini önbelleğe alır.</p><p>Dosyalar değiştiğinde ImgBed dizin cache version değerini günceller ve sonraki istekler candidate pool&#39;u yeniden oluşturur. Boş dizinler tekrar eden sorguları önlemek için kısa süre önbelleğe alınır.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery, ziyaretçilerin görmesine izin verdiğiniz dizinler için salt okunur herkese açık gezinme sayfası sağlar.</p><p>Etkinleştirildikten sonra ziyaretçiler şurayı açabilir:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-ayarları" tabindex="-1">Public Gallery Ayarları <a class="header-anchor" href="#public-gallery-ayarları" aria-label="Permalink to &quot;Public Gallery Ayarları&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Seçenek</th><th>Amaç</th></tr></thead><tbody><tr><td>Enable</td><td>Public gallery&#39;yi açar veya kapatır. Kapalıyken ziyaretçiler gezemez.</td></tr><tr><td>Image loading mode</td><td>Önizlemelerin özgün görselleri mi thumbnails değerlerini mi kullanacağını belirler.</td></tr><tr><td>Open directories</td><td>Ziyaretçilerin erişebileceği dizinleri belirler.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Amaç</th></tr></thead><tbody><tr><td>Original</td><td>Ziyaretçi sayfası özgün dosyaları doğrudan yükler.</td></tr><tr><td>Thumbnail</td><td>Ziyaretçi sayfası daha hızlı yükleme için thumbnails tercih eder.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories ziyaretçilerin ne görebileceğini belirler.</p><p>Örneğin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Ziyaretçiler şunlara erişebilir:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p><code>/2026/lucky/</code> gibi alt dizinler de açılabilir. Açık olmayan dizinlere ziyaretçiler engellenir.</p><h2 id="public-gallery-ozellikleri" tabindex="-1">Public Gallery Özellikleri <a class="header-anchor" href="#public-gallery-ozellikleri" aria-label="Permalink to &quot;Public Gallery Özellikleri&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Özellik</th><th>Açıklama</th></tr></thead><tbody><tr><td>Browse directories</td><td>Açık dizinlerdeki dosyaları ve alt dizinleri görüntüler.</td></tr><tr><td>Search</td><td>File name, file ID veya tags ile arama yapar.</td></tr><tr><td>Type filter</td><td>Images, videos, audio veya diğer dosyaları filtreler.</td></tr><tr><td>Tag filter</td><td>Seçili tags değerlerini dahil eder veya hariç tutar.</td></tr><tr><td>Orientation filter</td><td>Landscape veya portrait images filtreler.</td></tr><tr><td>Time filter</td><td>Upload time aralığına göre filtreler.</td></tr><tr><td>Extension filter</td><td>File extension değerine göre filtreler.</td></tr><tr><td>Copy link</td><td>File access links kopyalar.</td></tr><tr><td>Media preview</td><td>Ziyaretçi sayfasında images, videos ve audio görüntüler veya oynatır.</td></tr></tbody></table><h2 id="public-gallery-erisim-kuralları" tabindex="-1">Public Gallery Erişim Kuralları <a class="header-anchor" href="#public-gallery-erisim-kuralları" aria-label="Permalink to &quot;Public Gallery Erişim Kuralları&quot;">​</a></h2><p>Public gallery de public access rules kurallarına uyar:</p><table tabindex="0"><thead><tr><th>Kural</th><th>Etki</th></tr></thead><tbody><tr><td>Open directories</td><td>Yalnızca izin verilen dizinler gösterilir.</td></tr><tr><td>Access mode</td><td>İçerik geçerli age-rating access mode ile filtrelenir.</td></tr><tr><td>Allowlist mode</td><td>Etkin olduğunda yalnızca public access için izinli dosyalar gösterilir.</td></tr><tr><td>Blocklist</td><td>Blocklisted files gizlenir.</td></tr></tbody></table>`,43)])])}const u=a(d,[["render",l]]);export{m as __pageData,u as default};
